//  TERRIBLE PERFORMANCE: 
// We read the width (Layout), then write a new width (Layout), 1000 times in a row.
for (let i = 0; i < 1000; i++) {
  const width = box.offsetWidth; 
  box.style.width = width + 1 + 'px'; 
}

//  GREAT PERFORMANCE:
// We read the width ONCE. Do the math in pure JS memory. Then write the DOM ONCE.
let width = box.offsetWidth;
for (let i = 0; i < 1000; i++) {
  width += 1;
}
box.style.width = width + 'px';
